    let manifest = RBTDGC_INSCRIBE_RELIQUARY;
    let err = rbtdrm_verify(manifest, RBTDRM_FIXTURE_ONBOARDING_SEQUENCE).unwrap_err();
    assert!(err.contains(RBTDGC_YOKE_RELIQUARY));
