fn rbtdtm_accepts_valid_handbook_render_manifest() {
    let manifest = rbtdtm_manifest_for(RBTDRM_FIXTURE_HANDBOOK_RENDER);
    assert!(rbtdrm_verify(&manifest, RBTDRM_FIXTURE_HANDBOOK_RENDER).is_ok());
}

