35	/// Build a manifest string from the required colophons for a fixture.
36	fn rbtdtm_manifest_for(fixture: &str) -> String {
37	    rbtdrm_required_colophons(fixture)
38	        .expect("unknown fixture")
39	        .join(" ")
40	}
